import * as React from "react"
import { Link, graphql } from "gatsby"
import Layout from "../../components/Layout"
import Seo from "../../components/Seo"
import * as styles from "../../styles/sass/project-home.module.scss"

const Projects = ({ data }) => {
  const projects = data.allMarkdownRemark.nodes

  return (
    <Layout>
      <div className="container-fluid px-4" style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <div className={styles.container}>
          <h1 className={styles.projectHeading}>Projects at a glance</h1>

          <div className={styles.projectContainer}>
            {projects.map(project => (
              <Link
                to={`/projects/${project.frontmatter.slug}`}
                key={project.id}
                className={`${styles.projectCard} glass glass-hover`}
              >
                <p className={styles.pStack}>{project.frontmatter.stack}</p>
                <h2 className={styles.pTitle}>{project.frontmatter.title}</h2>
                <div className={styles.pExcerpt}>{project.excerpt}</div>
                <div className="mt-auto pt-3 text-white small" style={{ fontWeight: 600 }}>
                  View Project &rarr;
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </Layout>
  )
}

export const query = graphql`
  query ProjectsPage {
    allMarkdownRemark(
      sort: { frontmatter: { title: ASC } }
      filter: { frontmatter: { type: { eq: "project" } } }
    ) {
      nodes {
        frontmatter {
          slug
          stack
          title
        }
        id
        excerpt(format: PLAIN, pruneLength: 180)
      }
    }
  }
`

export const Head = () => <Seo title="Projects" />

export default Projects
